function debug_playToEndRound() {
  $currentRound = $this->globals->get(ROUND);
  $security = 0;
  // make sure the condition will not create an infinite loop!
  while ($this->globals->get(ROUND) == $currentRound && $security < 100) {
    $security++;
    foreach($this->gamestate->getActivePlayerList() as $playerId) {
        $playerId = (int)$playerId;
        $this->gamestate->runStateClassZombie($this->gamestate->getCurrentState($playerId), $playerId);
    }
  }
}

protected function zombieTurn(array $state, int $active_player): void {
    $state_name = $state["name"];

    if ($state["type"] === "activeplayer") {
        switch ($state_name) {
            case 'state1':
                $this->zombieTurn_state1($active_player);
                break;
            case 'state2':
                $this->zombieTurn_state2($active_player);
                break;
            case 'state3':
                $this->zombieTurn_state3($active_player);
                break;
            }
            // ... handle all your states in the same fashion
        }

        return;
    }

    // Make sure player is in a non-blocking status for role turn.
    if ($state["type"] === "multipleactiveplayer") {
        // this example is a Zombie level 0, for level 1 or more, it would be similar to the examples you can see for activeplayer states.
        $this->gamestate->setPlayerNonMultiactive($active_player, '');
        return;
    }

    throw new \feException("Zombie mode not supported at this game state: \"{$state_name}\".");
}

protected function zombieTurn_state1(int $active_player): void {
    $this->gamestate->nextState("zombiePass"); // you need to declare this transition that will bring the player/bot to the next state.
}

